import type {
  DmPolicy,
  GroupPolicy,
  GroupToolPolicyBySenderConfig,
  GroupToolPolicyConfig,
  OpenClawConfig,
} from "./runtime-api.js";

/**
 * Minimal MarkdownConfig shape — mirrors the core type without a direct import.
 * Only the `tables` field is supported; extend as needed.
 */
export type PulseBoardMarkdownConfig = {
  tables?: "off" | "bullets" | "code" | "block";
};

/**
 * Minimal probe result shape — mirrors the core BaseProbeResult type.
 */
export type BaseProbeResult<TError = string | null> = {
  ok: boolean;
  error?: TError;
};

/** Per-board (group) configuration. */
export type PulseBoardBoardConfig = {
  requireMention?: boolean;
  enabled?: boolean;
  allowFrom?: Array<string | number>;
  tools?: GroupToolPolicyConfig;
  toolsBySender?: GroupToolPolicyBySenderConfig;
  skills?: string[];
  systemPrompt?: string;
};

/** Per-account PulseBoard configuration. */
export type PulseBoardAccountConfig = {
  name?: string;
  enabled?: boolean;
  /** PulseBoard API base URL (default: https://api.pulseboard.io). */
  apiUrl?: string;
  /** API bearer token (sensitive). */
  token?: string;
  /** Path to a file containing the API bearer token. */
  tokenFile?: string;
  /** The bot's PulseBoard username used to identify self-authored messages and @mention targets. */
  username?: string;
  dmPolicy?: DmPolicy;
  allowFrom?: Array<string | number>;
  groupPolicy?: GroupPolicy;
  groupAllowFrom?: Array<string | number>;
  /** Board-specific overrides keyed by normalized board id (e.g. "#announcements"). */
  boards?: Record<string, PulseBoardBoardConfig>;
  defaultTo?: string;
  textChunkLimit?: number;
  markdown?: PulseBoardMarkdownConfig;
  historyLimit?: number;
  dmHistoryLimit?: number;
};

/** Root channels.pulseboard config (may include sub-accounts). */
export type PulseBoardConfig = PulseBoardAccountConfig & {
  accounts?: Record<string, PulseBoardAccountConfig>;
  defaultAccount?: string;
};

/** Augmented OpenClaw config used inside this extension. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardConfig;
  };
};

/** A single inbound message received from PulseBoard. */
export type PulseBoardInboundMessage = {
  messageId: string;
  /** Board id (e.g. "#general") for board posts; sender username for direct messages. */
  target: string;
  /** Username of the sender. */
  senderId: string;
  text: string;
  timestamp: number;
  /** true when the message arrived on a board; false for a direct message. */
  isBoard: boolean;
};

/** Probe result for PulseBoard. */
export type PulseBoardProbe = BaseProbeResult<string> & {
  apiUrl: string;
  username: string;
  latencyMs?: number;
};

