/** Normalized board id prefix. */
const BOARD_PREFIX = "#";

/** Regex: valid PulseBoard username or board slug — alphanumeric + hyphens/underscores/dots. */
const VALID_SLUG_RE = /^[a-zA-Z0-9_\-.]+$/u;

/**
 * Returns true when a normalized target refers to a board (group conversation).
 * Boards begin with "#".
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith(BOARD_PREFIX);
}

/**
 * Returns true when the raw string looks like a valid PulseBoard target id
 * (either a board slug prefixed with "#" or a plain username slug).
 */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  const slug = trimmed.startsWith(BOARD_PREFIX) ? trimmed.slice(1) : trimmed;
  return slug.length > 0 && VALID_SLUG_RE.test(slug);
}

/**
 * Normalizes a raw messaging target to a canonical PulseBoard id.
 *
 * Accepted input forms:
 *   - "#boardname"             → "#boardname"  (board)
 *   - "board:boardname"        → "#boardname"  (board)
 *   - "pulseboard:#boardname"  → "#boardname"  (board)
 *   - "@username"              → "username"    (DM)
 *   - "user:username"          → "username"    (DM)
 *   - "pulseboard:username"    → "username"    (DM)
 *   - "username"               → "username"    (DM)
 *
 * Returns undefined for malformed or empty inputs.
 */
export function normalizePulseBoardTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) {
    return undefined;
  }

  // Strip the "pulseboard:" scheme prefix if present.
  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Handle "board:" prefix → convert to "#" notation.
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith(BOARD_PREFIX)) {
      target = `${BOARD_PREFIX}${target}`;
    }
  }

  // Handle "user:" prefix.
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  // Strip a leading "@" for DMs (not boards).
  if (target.startsWith("@") && !target.startsWith("#")) {
    target = target.slice(1).trim();
  }

  if (!target || !looksLikePulseBoardTargetId(target)) {
    return undefined;
  }

  return target;
}

/**
 * Normalizes a raw allowlist entry to a lowercase username.
 * Strips "pulseboard:", "user:", and "@" prefixes.
 * Returns an empty string for invalid inputs.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

/** Normalizes a list of raw allow-from entries to lowercase usernames. */
export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((e) => normalizePulseBoardAllowEntry(String(e))).filter(Boolean);
}

