/**
 * Resolves which board config entry (if any) matches the inbound target.
 * Board keys are compared case-insensitively.
 */
export function resolvePulseBoardGroupMatch(params: {
  boards?: Record<string, PulseBoardBoardConfig>;
  target: string;
}): PulseBoardGroupMatch {
  const boards = params.boards ?? {};
  const hasConfiguredBoards = Object.keys(boards).length > 0;

  // Exact match first.
  const direct = boards[params.target];
  if (direct) {
    return { allowed: true, boardConfig: direct, wildcardConfig: boards["*"], hasConfiguredBoards };
  }

  // Case-insensitive fallback.
  const targetLower = params.target.toLowerCase();
  const directKey = Object.keys(boards).find((k) => k.toLowerCase() === targetLower);
  if (directKey) {
    const matched = boards[directKey];
    if (matched) {
      return {
        allowed: true,
        boardConfig: matched,
        wildcardConfig: boards["*"],
        hasConfiguredBoards,
