import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardTarget, isBoardTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

type SendPulseBoardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

/**
 * Makes an authenticated POST request to the PulseBoard API to deliver a message.
 *
 * For boards: POST /boards/{boardId}/messages
 * For DMs:    POST /users/{userId}/messages
 *
 * PulseBoard responds with `{ id: string }` on success.
 */
async function callPulseBoardApi(params: {
  apiUrl: string;
  token: string;
  target: string;
  text: string;
  replyTo?: string;
}): Promise<string> {
  const { apiUrl, token, target, text, replyTo } = params;
  const isBoard = isBoardTarget(target);

