    );
  }

  const target = normalizePulseBoardTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const payload = text.trim();
  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends");
  }

  const messageId = await callPulseBoardApi({
    apiUrl: account.apiUrl,
    token: account.token,
    target,
    text: payload,
    replyTo: opts.replyTo,
  });

  recordOutboundActivity(account.accountId);

  return { messageId, target };
}

