import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import {
  dispatchInboundDirectDmWithRuntime,
  logInboundDrop,
  resolveInboundSessionEnvelopeContext,
} from "openclaw/plugin-sdk/channel-inbound";
import {
  createNormalizedOutboundDeliverer,
  deliverFormattedTextWithAttachments,
  type OutboundReplyPayload,
} from "openclaw/plugin-sdk/reply-payload";
import {
  GROUP_POLICY_BLOCKED_LABEL,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  warnMissingProviderGroupPolicyFallbackOnce,
} from "openclaw/plugin-sdk/runtime-group-policy";
import type { ResolvedPulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardAllowlist } from "./normalize.js";
import {
  resolvePulseBoardGroupMatch,
  resolvePulseBoardGroupAccessGate,
  resolvePulseBoardRequireMention,
  resolvePulseBoardGroupSenderAllowed,
} from "./policy.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

async function deliverPulseBoardReply(params: {
  payload: OutboundReplyPayload;
  target: string;
  accountId: string;
  sendReply?: (target: string, text: string) => Promise<void>;
}): Promise<void> {
  await deliverFormattedTextWithAttachments({
    payload: params.payload,
    send: async ({ text }) => {
      if (params.sendReply) {
        await params.sendReply(params.target, text);
      } else {
        await sendMessagePulseBoard(params.target, text, { accountId: params.accountId });
      }
    },
  });
}

/**
 * Dispatches an inbound PulseBoard board (group) message through the core
 * routing and reply pipeline.
 *
 * NOTE: This uses lower-level runtime APIs directly because the public plugin
 * SDK does not yet expose a `dispatchInboundGroupMessageWithRuntime` helper.
 * A future `openclaw/plugin-sdk/pulseboard` module would wrap this.
 */
async function dispatchPulseBoardBoardInbound(params: {
  core: ReturnType<typeof getPulseBoardRuntime>;
  config: CoreConfig;
  account: ResolvedPulseBoardAccount;
  message: PulseBoardInboundMessage;
  sendReply?: (target: string, text: string) => Promise<void>;
  runtime: RuntimeEnv;
  commandAuthorized?: boolean;
  groupSystemPrompt?: string;
}): Promise<void> {
  const { core, config, account, message, runtime } = params;
  const boardId = message.target;

  const route = core.channel.routing.resolveAgentRoute({
    cfg: config,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    peer: { kind: "group", id: boardId },
  });

  const { storePath, envelopeOptions, previousTimestamp } = resolveInboundSessionEnvelopeContext({
    cfg: config,
    agentId: route.agentId,
    sessionKey: route.sessionKey,
  });

  const body = core.channel.reply.formatAgentEnvelope({
    channel: "PulseBoard",
    from: boardId,
    timestamp: message.timestamp,
    previousTimestamp,
    envelope: envelopeOptions,
    body: message.text,
  });

  const ctxPayload = core.channel.reply.finalizeInboundContext({
    Body: body,
    RawBody: message.text,
    CommandBody: message.text,
    From: `pulseboard:board:${boardId}`,
    To: `pulseboard:${boardId}`,
    SessionKey: route.sessionKey,
    AccountId: route.accountId,
    ChatType: "group",
    ConversationLabel: boardId,
    SenderName: message.senderId,
    SenderId: message.senderId,
    GroupSubject: boardId,
    GroupSystemPrompt: params.groupSystemPrompt ?? undefined,
    Provider: CHANNEL_ID,
    Surface: CHANNEL_ID,
    MessageSid: message.messageId,
    Timestamp: message.timestamp,
    OriginatingChannel: CHANNEL_ID,
    OriginatingTo: `pulseboard:${boardId}`,
    CommandAuthorized: params.commandAuthorized,
  });

  // Record inbound session (non-blocking error handling).
  await core.channel.session.recordInboundSession({
    storePath,
    sessionKey: route.sessionKey,
    ctx: ctxPayload,
    onRecordError: (err) => {
      runtime.error?.(`pulseboard: failed recording board session: ${String(err)}`);
    },
  });

  // Deliver via buffered block dispatcher.
  await core.channel.reply.dispatchReplyWithBufferedBlockDispatcher({
    ctx: ctxPayload,
    cfg: config,
    dispatcherOptions: {
      deliver: createNormalizedOutboundDeliverer(async (payload) => {
        await deliverPulseBoardReply({
          payload,
          target: boardId,
          accountId: account.accountId,
          sendReply: params.sendReply,
        });
      }),
      onError: (err, info) => {
        runtime.error?.(
          `pulseboard board ${String(info.kind)} reply failed: ${String(err)}`,
        );
      },
    },
  });
}

/** Handles a single inbound PulseBoard message (DM or board). */
export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  sendReply?: (target: string, text: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime, statusSink } = params;
  const core = getPulseBoardRuntime();
  const pairing = createChannelPairingController({
    core,
    channel: CHANNEL_ID,
    accountId: account.accountId,
  });

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  statusSink?.({ lastInboundAt: message.timestamp });

  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
  const { groupPolicy, providerMissingFallbackApplied } =
    resolveAllowlistProviderRuntimeGroupPolicy({
      providerConfigPresent: config.channels?.pulseboard !== undefined,
      groupPolicy: account.config.groupPolicy,
      defaultGroupPolicy,
    });
  warnMissingProviderGroupPolicyFallbackOnce({
    providerMissingFallbackApplied,
    providerKey: "pulseboard",
    accountId: account.accountId,
    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
    log: (msg) => runtime.log?.(msg),
  });

  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);
  const configGroupAllowFrom = normalizePulseBoardAllowlist(account.config.groupAllowFrom);

  if (message.isBoard) {
    // ---- Board (group) message ----
    const groupMatch = resolvePulseBoardGroupMatch({
      boards: account.config.boards,
      target: message.target,
    });

    const groupAccess = resolvePulseBoardGroupAccessGate({ groupPolicy, groupMatch });
    if (!groupAccess.allowed) {
      logInboundDrop({
        log: (line) => runtime.log?.(line),
        channel: CHANNEL_ID,
        reason: groupAccess.reason,
        target: message.target,
      });
      return;
    }

    const innerAllowFrom = normalizePulseBoardAllowlist(groupMatch.boardConfig?.allowFrom);
    const wildcardAllowFrom = normalizePulseBoardAllowlist(groupMatch.wildcardConfig?.allowFrom);
    const boardAllowFrom = innerAllowFrom.length > 0 ? innerAllowFrom : wildcardAllowFrom;

    const senderAllowed = resolvePulseBoardGroupSenderAllowed({
      groupPolicy,
      senderId: message.senderId,
      outerAllowFrom: configGroupAllowFrom,
      innerAllowFrom: boardAllowFrom,
    });
    if (!senderAllowed) {
      runtime.log?.(
        `pulseboard: drop board sender ${message.senderId} (policy=${groupPolicy})`,
      );
      return;
    }

    // Mention gating: board messages require @botname unless requireMention=false.
    const requireMention = resolvePulseBoardRequireMention({
      boardConfig: groupMatch.boardConfig,
      wildcardConfig: groupMatch.wildcardConfig,
    });
    const botUsername = account.username.trim().toLowerCase();
    const mentionRegex = botUsername
      ? new RegExp(`@${botUsername.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i")
      : null;
    const wasMentioned = mentionRegex ? mentionRegex.test(rawBody) : false;

    if (requireMention && !wasMentioned) {
      runtime.log?.(`pulseboard: drop board ${message.target} (missing-mention)`);
      return;
    }

    const groupSystemPrompt = groupMatch.boardConfig?.systemPrompt?.trim() || undefined;

    await dispatchPulseBoardBoardInbound({
      core,
      config,
      account,
      message,
      sendReply: params.sendReply,
      runtime,
      groupSystemPrompt,
    });
    statusSink?.({ lastOutboundAt: Date.now() });
  } else {
    // ---- Direct message ----
    if (dmPolicy === "disabled") {
      runtime.log?.(`pulseboard: drop DM sender=${message.senderId} (dmPolicy=disabled)`);
      return;
    }

    const senderLc = message.senderId.toLowerCase();
    const isDmAllowed =
      dmPolicy === "open" ||
      configAllowFrom.includes("*") ||
      configAllowFrom.includes(senderLc);

    if (!isDmAllowed) {
      if (dmPolicy === "pairing") {
        await pairing.issueChallenge({
          senderId: senderLc,
          senderIdLine: `Your PulseBoard username: ${message.senderId}`,
          meta: { name: message.senderId },
          sendPairingReply: async (text) => {
            await deliverPulseBoardReply({
              payload: { text },
              target: message.senderId,
              accountId: account.accountId,
              sendReply: params.sendReply,
            });
          },
          onReplyError: (err) => {
            runtime.error?.(
              `pulseboard: pairing reply failed for ${message.senderId}: ${String(err)}`,
            );
          },
        });
      }
      runtime.log?.(`pulseboard: drop DM sender ${message.senderId} (dmPolicy=${dmPolicy})`);
      return;
    }

    await dispatchInboundDirectDmWithRuntime({
      cfg: config,
      runtime: core,
      channel: CHANNEL_ID,
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: message.senderId },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:${account.username || account.accountId}`,
      conversationLabel: message.senderId,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      deliver: async (payload) => {
        await deliverPulseBoardReply({
          payload,
          target: message.senderId,
          accountId: account.accountId,
          sendReply: params.sendReply,
        });
        statusSink?.({ lastOutboundAt: Date.now() });
      },
      onRecordError: (err) => {
        runtime.error?.(`pulseboard: failed recording DM session: ${String(err)}`);
      },
      onDispatchError: (err, info) => {
        runtime.error?.(`pulseboard DM ${info.kind} reply failed: ${String(err)}`);
      },
    });
  }
}

