    accountId: account.accountId,
  });

  const rawBody = message.text?.trim() ?? "";
  if (!rawBody) {
    return;
  }

  statusSink?.({ lastInboundAt: message.timestamp });

  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const defaultGroupPolicy = resolveDefaultGroupPolicy(config);
  const { groupPolicy, providerMissingFallbackApplied } =
    resolveAllowlistProviderRuntimeGroupPolicy({
      providerConfigPresent: config.channels?.pulseboard !== undefined,
      groupPolicy: account.config.groupPolicy,
      defaultGroupPolicy,
    });
  warnMissingProviderGroupPolicyFallbackOnce({
    providerMissingFallbackApplied,
    providerKey: "pulseboard",
    accountId: account.accountId,
    blockedLabel: GROUP_POLICY_BLOCKED_LABEL.channel,
    log: (msg) => runtime.log?.(msg),
  });

  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);
  const configGroupAllowFrom = normalizePulseBoardAllowlist(account.config.groupAllowFrom);

  if (message.isBoard) {
    // ---- Board (group) message ----
    const groupMatch = resolvePulseBoardGroupMatch({
      boards: account.config.boards,
      target: message.target,
    });

    const groupAccess = resolvePulseBoardGroupAccessGate({ groupPolicy, groupMatch });
    if (!groupAccess.allowed) {
      logInboundDrop({
        log: (line) => runtime.log?.(line),
        channel: CHANNEL_ID,
        reason: groupAccess.reason,
        target: message.target,
      });
      return;
    }

    const innerAllowFrom = normalizePulseBoardAllowlist(groupMatch.boardConfig?.allowFrom);
    const wildcardAllowFrom = normalizePulseBoardAllowlist(groupMatch.wildcardConfig?.allowFrom);
    const boardAllowFrom = innerAllowFrom.length > 0 ? innerAllowFrom : wildcardAllowFrom;

    const senderAllowed = resolvePulseBoardGroupSenderAllowed({
      groupPolicy,
      senderId: message.senderId,
      outerAllowFrom: configGroupAllowFrom,
      innerAllowFrom: boardAllowFrom,
    });
    if (!senderAllowed) {
      runtime.log?.(
        `pulseboard: drop board sender ${message.senderId} (policy=${groupPolicy})`,
      );
      return;
    }

    // Mention gating: board messages require @botname unless requireMention=false.
    const requireMention = resolvePulseBoardRequireMention({
      boardConfig: groupMatch.boardConfig,
      wildcardConfig: groupMatch.wildcardConfig,
    });
    const botUsername = account.username.trim().toLowerCase();
    const mentionRegex = botUsername
      ? new RegExp(`@${botUsername.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i")
      : null;
    const wasMentioned = mentionRegex ? mentionRegex.test(rawBody) : false;

    if (requireMention && !wasMentioned) {
      runtime.log?.(`pulseboard: drop board ${message.target} (missing-mention)`);
      return;
    }

    const groupSystemPrompt = groupMatch.boardConfig?.systemPrompt?.trim() || undefined;

    await dispatchPulseBoardBoardInbound({
      core,
      config,
      account,
      message,
      sendReply: params.sendReply,
      runtime,
      groupSystemPrompt,
    });
    statusSink?.({ lastOutboundAt: Date.now() });
  } else {
    // ---- Direct message ----
    if (dmPolicy === "disabled") {
      runtime.log?.(`pulseboard: drop DM sender=${message.senderId} (dmPolicy=disabled)`);
      return;
    }

    const senderLc = message.senderId.toLowerCase();
    const isDmAllowed =
      dmPolicy === "open" ||
      configAllowFrom.includes("*") ||
      configAllowFrom.includes(senderLc);

    if (!isDmAllowed) {
      if (dmPolicy === "pairing") {
        await pairing.issueChallenge({
          senderId: senderLc,
          senderIdLine: `Your PulseBoard username: ${message.senderId}`,
          meta: { name: message.senderId },
          sendPairingReply: async (text) => {
            await deliverPulseBoardReply({
              payload: { text },
              target: message.senderId,
              accountId: account.accountId,
              sendReply: params.sendReply,
            });
          },
          onReplyError: (err) => {
            runtime.error?.(
              `pulseboard: pairing reply failed for ${message.senderId}: ${String(err)}`,
            );
          },
        });
      }
      runtime.log?.(`pulseboard: drop DM sender ${message.senderId} (dmPolicy=${dmPolicy})`);
      return;
    }

    await dispatchInboundDirectDmWithRuntime({
      cfg: config,
      runtime: core,
      channel: CHANNEL_ID,
      channelLabel: "PulseBoard",
      accountId: account.accountId,
      peer: { kind: "direct", id: message.senderId },
      senderId: message.senderId,
      senderAddress: `pulseboard:${message.senderId}`,
      recipientAddress: `pulseboard:${account.username || account.accountId}`,
      conversationLabel: message.senderId,
      rawBody,
      messageId: message.messageId,
      timestamp: message.timestamp,
      deliver: async (payload) => {
        await deliverPulseBoardReply({
          payload,
          target: message.senderId,
          accountId: account.accountId,
          sendReply: params.sendReply,
        });
        statusSink?.({ lastOutboundAt: Date.now() });
      },
      onRecordError: (err) => {
        runtime.error?.(`pulseboard: failed recording DM session: ${String(err)}`);
      },
      onDispatchError: (err, info) => {
        runtime.error?.(`pulseboard DM ${info.kind} reply failed: ${String(err)}`);
      },
    });
  }
}

