import { resolvePulseBoardAccount } from "./accounts.js";
import { isBoardTarget } from "./normalize.js";
import { handlePulseBoardInbound } from "./inbound.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
  /** Polling interval in milliseconds (default: 5000). */
  pollIntervalMs?: number;
};

/**
 * Resolves whether a raw event target is a board post or a direct message.
 * PulseBoard's event API returns `"board"` or `"dm"` in the `type` field.
 */
function resolveEventTarget(event: {
  type: "board" | "dm";
  boardId?: string;
  senderId: string;
}): { target: string; isBoard: boolean } {
  if (event.type === "board" && event.boardId) {
    // Board ids come prefixed with "#" from the API.
    const target = event.boardId.startsWith("#") ? event.boardId : `#${event.boardId}`;
    return { target, isBoard: true };
  }
  return { target: event.senderId, isBoard: false };
}

/**
 * Polls the PulseBoard events endpoint for new messages.
 *
 * The fictional PulseBoard API exposes:
 *   GET /events?since={cursor}&limit=50
 * returning `{ events: PulseBoardEvent[], cursor: string }`.
 */
async function pollPulseBoardEvents(params: {
  apiUrl: string;
  token: string;
  cursor: string;
  signal?: AbortSignal;
}): Promise<{ messages: PulseBoardInboundMessage[]; cursor: string }> {
  const url = `${params.apiUrl.replace(/\/+$/, "")}/events?since=${encodeURIComponent(params.cursor)}&limit=50`;
  const response = await fetch(url, {
    headers: { Authorization: `Bearer ${params.token}` },
    signal: params.signal,
  });

  if (!response.ok) {
    throw new Error(`PulseBoard events poll failed: HTTP ${response.status}`);
  }

  const data = (await response.json()) as {
    events?: Array<{
      id: string;
      type: "board" | "dm";
      boardId?: string;
      senderId: string;
      text: string;
      timestamp: number;
    }>;
    cursor?: string;
  };

  const events = data.events ?? [];
  const nextCursor = data.cursor ?? params.cursor;

  const messages: PulseBoardInboundMessage[] = events.map((event) => {
    const { target, isBoard } = resolveEventTarget(event);
    return {
      messageId: event.id,
      target,
      senderId: event.senderId,
      text: event.text,
      timestamp: event.timestamp,
      isBoard,
    };
  });

  return { messages, cursor: nextCursor };
}

/** Starts a polling-based monitor for PulseBoard inbound messages. */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  // Resolve a lightweight logger-compatible runtime env from core logging.
  const runtime: RuntimeEnv = {
    log: (msg) => core.logging.getChildLogger().debug?.(msg),
    error: (msg) => core.logging.getChildLogger().error(msg),
  };

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need a token in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({ channel: "pulseboard", accountId: account.accountId });
  logger.info(
    `[${account.accountId}] starting PulseBoard monitor (${account.apiUrl})`,
  );

  const pollIntervalMs = opts.pollIntervalMs ?? 5000;
  let stopped = false;
  let cursor = String(Date.now());

  // Self-correcting poll loop: on error, log and continue after the interval.
  const pollLoop = async () => {
    while (!stopped && !(opts.abortSignal?.aborted)) {
      try {
        const { messages, cursor: nextCursor } = await pollPulseBoardEvents({
          apiUrl: account.apiUrl,
          token: account.token,
          cursor,
          signal: opts.abortSignal,
        });
        cursor = nextCursor;

        for (const message of messages) {
          // Skip messages sent by the bot itself.
          if (
            account.username &&
            message.senderId.toLowerCase() === account.username.toLowerCase()
          ) {
            continue;
          }

          core.channel.activity.record({
            channel: "pulseboard",
            accountId: account.accountId,
            direction: "inbound",
            at: message.timestamp,
          });

          if (opts.onMessage) {
            await opts.onMessage(message);
            continue;
          }

          await handlePulseBoardInbound({
            message,
            account,
            config: cfg,
            runtime,
            statusSink: opts.statusSink,
          });
        }
      } catch (err) {
        if (stopped || opts.abortSignal?.aborted) {
          break;
        }
        logger.error(`[${account.accountId}] PulseBoard poll error: ${String(err)}`);
      }

      // Wait for the next poll interval (or until abort).
      await new Promise<void>((resolve) => {
        const timer = setTimeout(resolve, pollIntervalMs);
        opts.abortSignal?.addEventListener("abort", () => {
          clearTimeout(timer);
          resolve();
        });
      });
    }
  };

  // Fire off the poll loop; intentional floating promise — the caller uses
  // the returned stop() to terminate it via opts.abortSignal.
  void pollLoop();

  return {
    stop: () => {
      stopped = true;
    },
  };
}

// Re-export the board target check for use by monitor consumers.
export { isBoardTarget };

