import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  normalizePulseBoardTarget,
} from "./normalize.js";

describe("isBoardTarget", () => {
  it("returns true for board ids starting with #", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#announcements")).toBe(true);
  });

  it("returns false for usernames", () => {
    expect(isBoardTarget("alice")).toBe(false);
    expect(isBoardTarget("")).toBe(false);
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("returns true for valid board ids", () => {
    expect(looksLikePulseBoardTargetId("#general")).toBe(true);
    expect(looksLikePulseBoardTargetId("#my-board")).toBe(true);
  });

  it("returns true for valid usernames", () => {
    expect(looksLikePulseBoardTargetId("alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("bot_user")).toBe(true);
  });

  it("returns false for empty or invalid input", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
    expect(looksLikePulseBoardTargetId("  ")).toBe(false);
    expect(looksLikePulseBoardTargetId("hello world")).toBe(false);
  });
});

describe("normalizePulseBoardTarget", () => {
  it("normalizes board targets", () => {
    expect(normalizePulseBoardTarget("#general")).toBe("#general");
    expect(normalizePulseBoardTarget("board:general")).toBe("#general");
    expect(normalizePulseBoardTarget("board:#general")).toBe("#general");
    expect(normalizePulseBoardTarget("pulseboard:#general")).toBe("#general");
    expect(normalizePulseBoardTarget("pulseboard:board:general")).toBe("#general");
  });

  it("normalizes user targets", () => {
    expect(normalizePulseBoardTarget("alice")).toBe("alice");
    expect(normalizePulseBoardTarget("@alice")).toBe("alice");
    expect(normalizePulseBoardTarget("user:alice")).toBe("alice");
