import { normalizePulseBoardAllowlist } from "./normalize.js";
import type { PulseBoardAccountConfig, PulseBoardBoardConfig } from "./types.js";

export type PulseBoardGroupMatch = {
  allowed: boolean;
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
  hasConfiguredBoards: boolean;
};

export type PulseBoardGroupAccessGate = {
  allowed: boolean;
  reason: string;
};

/**
 * Resolves which board config entry (if any) matches the inbound target.
 * Board keys are compared case-insensitively.
 */
export function resolvePulseBoardGroupMatch(params: {
  boards?: Record<string, PulseBoardBoardConfig>;
  target: string;
}): PulseBoardGroupMatch {
  const boards = params.boards ?? {};
  const hasConfiguredBoards = Object.keys(boards).length > 0;

  // Exact match first.
  const direct = boards[params.target];
  if (direct) {
    return { allowed: true, boardConfig: direct, wildcardConfig: boards["*"], hasConfiguredBoards };
  }

  // Case-insensitive fallback.
  const targetLower = params.target.toLowerCase();
  const directKey = Object.keys(boards).find((k) => k.toLowerCase() === targetLower);
  if (directKey) {
    const matched = boards[directKey];
    if (matched) {
      return {
        allowed: true,
        boardConfig: matched,
        wildcardConfig: boards["*"],
        hasConfiguredBoards,
      };
    }
  }

  // Wildcard fallback.
  const wildcard = boards["*"];
  if (wildcard) {
    return { allowed: true, wildcardConfig: wildcard, hasConfiguredBoards };
  }

  return { allowed: false, hasConfiguredBoards };
}

/** Resolves whether an inbound board message is permitted by the group policy. */
export function resolvePulseBoardGroupAccessGate(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  groupMatch: PulseBoardGroupMatch;
}): PulseBoardGroupAccessGate {
  const policy = params.groupPolicy ?? "allowlist";
  if (policy === "disabled") {
    return { allowed: false, reason: "groupPolicy=disabled" };
  }
  if (policy === "allowlist") {
    if (!params.groupMatch.hasConfiguredBoards) {
      return { allowed: false, reason: "groupPolicy=allowlist and no boards configured" };
    }
    if (!params.groupMatch.allowed) {
      return { allowed: false, reason: "not allowlisted" };
    }
  }
  if (
    params.groupMatch.boardConfig?.enabled === false ||
    params.groupMatch.wildcardConfig?.enabled === false
  ) {
    return { allowed: false, reason: "disabled" };
  }
  return { allowed: true, reason: policy === "open" ? "open" : "allowlisted" };
}

/**
 * Resolves whether an @mention is required to trigger a reply on a board.
 * Defaults to true (mention-gated by default).
 */
export function resolvePulseBoardRequireMention(params: {
  boardConfig?: PulseBoardBoardConfig;
  wildcardConfig?: PulseBoardBoardConfig;
}): boolean {
  if (params.boardConfig?.requireMention !== undefined) {
    return params.boardConfig.requireMention;
  }
  if (params.wildcardConfig?.requireMention !== undefined) {
    return params.wildcardConfig.requireMention;
  }
  return true;
}

/**
 * Returns true when the sender is allowed to post to a board based on the group
 * and per-board allow-from lists.
 */
export function resolvePulseBoardGroupSenderAllowed(params: {
  groupPolicy: PulseBoardAccountConfig["groupPolicy"];
  senderId: string;
  outerAllowFrom: string[];
  innerAllowFrom: string[];
}): boolean {
  const policy = params.groupPolicy ?? "allowlist";
  const inner = normalizePulseBoardAllowlist(params.innerAllowFrom);
  const outer = normalizePulseBoardAllowlist(params.outerAllowFrom);
  const senderLc = params.senderId.toLowerCase();

  const check = (list: string[]) =>
    list.includes("*") || list.includes(senderLc);

  if (inner.length > 0) {
    return check(inner);
  }
  if (outer.length > 0) {
    return check(outer);
  }
  return policy === "open";
}

