      groupPolicy: "disabled",
      groupMatch: { allowed: true, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toContain("disabled");
  });

  it("blocks when policy=allowlist and no boards configured", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: { allowed: false, hasConfiguredBoards: false },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toContain("no boards configured");
  });

  it("blocks when policy=allowlist and target not in allowlist", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: { allowed: false, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("not allowlisted");
  });

  it("allows when policy=allowlist and target is allowlisted", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: { allowed: true, boardConfig: {}, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(true);
  });

  it("allows when policy=open regardless of match", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: "open",
      groupMatch: { allowed: false, hasConfiguredBoards: false },
    });
    expect(gate.allowed).toBe(true);
    expect(gate.reason).toBe("open");
  });

  it("blocks when boardConfig.enabled=false even if allowlisted", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: {
        allowed: true,
        boardConfig: { enabled: false },
        hasConfiguredBoards: true,
      },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("disabled");
  });

  it("blocks when wildcardConfig.enabled=false", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: "open",
      groupMatch: {
        allowed: true,
        wildcardConfig: { enabled: false },
        hasConfiguredBoards: true,
      },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("disabled");
  });

  it("defaults policy to allowlist when undefined", () => {
    const gate = resolvePulseBoardGroupAccessGate({
      groupPolicy: undefined,
      groupMatch: { allowed: false, hasConfiguredBoards: true },
    });
    expect(gate.allowed).toBe(false);
    expect(gate.reason).toBe("not allowlisted");
  });
});

// ---------------------------------------------------------------------------
// resolvePulseBoardRequireMention
// ---------------------------------------------------------------------------

describe("resolvePulseBoardRequireMention", () => {
  it("defaults to true when no configs provided", () => {
    expect(resolvePulseBoardRequireMention({})).toBe(true);
  });

  it("uses boardConfig.requireMention when set", () => {
    expect(
      resolvePulseBoardRequireMention({ boardConfig: { requireMention: false } }),
    ).toBe(false);
    expect(
      resolvePulseBoardRequireMention({ boardConfig: { requireMention: true } }),
    ).toBe(true);
  });

  it("falls back to wildcardConfig.requireMention when boardConfig lacks it", () => {
    expect(
      resolvePulseBoardRequireMention({
        boardConfig: {},
        wildcardConfig: { requireMention: false },
      }),
    ).toBe(false);
  });

  it("boardConfig takes precedence over wildcardConfig", () => {
    expect(
      resolvePulseBoardRequireMention({
        boardConfig: { requireMention: true },
        wildcardConfig: { requireMention: false },
      }),
    ).toBe(true);
  });
});

// ---------------------------------------------------------------------------
// resolvePulseBoardGroupSenderAllowed
// ---------------------------------------------------------------------------

describe("resolvePulseBoardGroupSenderAllowed", () => {
  it("allows sender in inner allowFrom list", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        senderId: "alice",
        outerAllowFrom: [],
        innerAllowFrom: ["alice", "bob"],
      }),
    ).toBe(true);
  });

  it("blocks sender not in inner allowFrom list", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        senderId: "carol",
        outerAllowFrom: [],
        innerAllowFrom: ["alice"],
      }),
    ).toBe(false);
  });

  it("falls through to outer allowFrom when inner is empty", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        senderId: "alice",
        outerAllowFrom: ["alice"],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("allows wildcard * in inner list", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        senderId: "anyone",
        outerAllowFrom: [],
        innerAllowFrom: ["*"],
      }),
    ).toBe(true);
  });

  it("allows wildcard * in outer list", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "open",
        senderId: "anyone",
        outerAllowFrom: ["*"],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("allows all senders when policy=open and no allowFrom lists", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "open",
        senderId: "stranger",
        outerAllowFrom: [],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("blocks all senders when policy=allowlist and no allowFrom lists", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        senderId: "stranger",
        outerAllowFrom: [],
        innerAllowFrom: [],
      }),
    ).toBe(false);
  });

  it("matches case-insensitively", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        senderId: "Alice",
        outerAllowFrom: [],
        innerAllowFrom: ["alice"],
      }),
    ).toBe(true);
  });
});
